const multer  = require('multer'); // Multer is a middleware package that handles file uploads. Install it in the project root directory via 'npm install --save multer' (or 'npm i multer')

function fileUploader(uploadDir, fileType) {
    let storage;
    if(fileType === "video") {
        const video = multer({
            dest: uploadDir // Specify target directory where uploaded files should be saved. This is necessary when using Multer, otherwise a new directory will be created in the project root dir by default at the same level as .js and .json files.
        });
        return video;
    } else {
        const image = multer({
            dest: uploadDir // Specify target directory where uploaded files should be saved. This is necessary when using Multer, otherwise a new directory will be created in the project root dir by default at the same level as .js and .json files.
        });
        return image;
    }
}

